INSERT INTO public.photos VALUES (21209, 'Margen Izquierda 1905', 'AHPZ. Estudio Coyne. 1905. "Vista del râ”œÂ¡o Ebro y el puente de Piedra." Imagen, al fondo, de la iglesia de Altabâ”œÃ­s y, a la derecha, del Cuartel de San Lâ”œÃ­zaro. Una columna de negro humo delata la actividad, mâ”œÃ­s al fondo, de una locomotora en acciâ”œâ”‚n, por la Estaciâ”œâ”‚n del Norte.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65618400, -0.87584800, '0101000020E6100000548B8862F206ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14951043130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14951043130.webp', 'https://www.flickr.com/photos/zaragozaantigua/14951043130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21361, 'Plaza de La Seo 1900', 'Imagen capturada en la plaza de La Seo con una vista parcial del cortejo municipal salido del homâ”œâ”‚nimo templo durante la celebraciâ”œâ”‚n, posiblemente, de la festividad del patrâ”œâ”‚n de la ciudad. Abren el cortejo a la izquierda los timbaleros portadores del tapiz con el escudo de Zaragoza, seguidos de los clarineros, los alguaciles y los maceros. Al fondo, fachada del Palacio Arzobispal con detalle de su portada de ingreso principal.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65523800, -0.87584800, '0101000020E6100000548B8862F206ECBF588CBAD6DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54788599605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54788599605.webp', 'https://www.flickr.com/photos/zaragozaantigua/54788599605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21369, 'El Ebro y la Seo 1918', 'Vista desde el Pilar del râ”œÂ¡o Ebro y la torre de la Seo, en 1918. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65552700, -0.87555800, '0101000020E61000009109F8359204ECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15089676224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15089676224.webp', 'https://www.flickr.com/photos/zaragozaantigua/15089676224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21375, 'Vista desde La Seo 1918', 'Una abierta mirada hacia el Suroeste de la ciudad desde uno de los ocho vanos del antiguo alminar nuevo de la mezquita aljama de Saraqusta, acrecentado en altura tras la conquista cristiana, y revestido de ropajes barrocos en el s.XVII. A los pies, el caserâ”œÂ¡o del barrio de La Seo, con algunos nuevos edificios en el eje de Don Jaime I, como el nâ”¬â•‘ 37, remodelado a finales del s.XIX, el nâ”¬â•‘ 41, edificado recientemente sobre la demolida iglesia de Santiago, y el nâ”¬â•‘ 35, aâ”œâ•‘n en obras, con proyecto de Albiâ”œâ–’ana. Muy cerca, sobresale la octogonal câ”œâ•‘pula y la torre de la iglesia de la Exaltaciâ”œâ”‚n de la Sta. Cruz, y la cercana plaza a la que da nombre. Una mirada panorâ”œÃ­mica, de izquierda a derecha, seâ”œâ–’ala varios hitos fundamentales: la mole cupular de Santiago el Mayor, los torreones laterales de la Audiencia, la Casa de la Misericordia (entre tinieblas), la torre de San Felipe, las torrecillas y câ”œâ•‘pula de los Escolapios, la alta torre de San Pablo, aparentemente al lado de la câ”œâ•‘pula y torres de Sta. Isabel. Cierra la visual, junto al florâ”œâ”‚n decorativo de la torre desde la que miramos, la chimenea de la "Alcoholera Agrâ”œÂ¡cola del Pilar", antes de convertirse en la "Azucarera Agrâ”œÂ¡cola del Pilar", en la calle 29 de septiembre. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15695294748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15695294748.webp', 'https://www.flickr.com/photos/zaragozaantigua/15695294748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21376, 'Cimborrio de la Seo 1918', 'Desde la torre de la Seo, imagen del Cimborrio mudâ”œÂ®jar (s.XIV) de la Catedral del Salvador, obra de Mahoma Ramâ”œÂ¡, en ladrillo, y rematado en una espadaâ”œâ–’a. A la izquierda, tras un callejeo por la calle del Sepulcro, visual de la torre de San Nicolâ”œÃ­s de Bari y del Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65482900, -0.87544000, '0101000020E6100000168733BF9A03ECBF77BCC96FD1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728009238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728009238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728009238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21382, 'Cimborrio de la Seo 1918', 'Habiendo ascendido algo mâ”œÃ­s en la torre de la Seo, nueva imagen del Cimborrio de la Catedral, obra de Mahoma Ramâ”œÂ¡, desde mâ”œÃ­s altura y â”œÃ­ngulo que permite una parcial pero muy interesante visual del antiguo barrio de la Seo. Asâ”œÂ¡, y la derecha, un poco a oscuras por estar en sombra, la reconocible puerta de la Aduana Vieja, en la plazuela del mismo nombre. Aunque ya fuera de plano, podremos seguir por la derecha, a travâ”œÂ®s de la calle de la Aduana Vieja, y llegar mentalmente a la Plaza del Reino, con todo o que ello supone. Torcemos hacia la izquierda, y nos metemos otra vez en la imagen por la calle del Chantre, algunos de cuyos edificios de viviendas asoman justo detrâ”œÃ­s del cimborrio de la Seo, ofreciâ”œÂ®ndonos sus modestas fachadas, en la abigarrada manzana de casas entre Chantre y Gavâ”œÂ¡n. Justo por aquâ”œÂ¡ pasa la actual San Vicente de Paâ”œâ•‘l, como por encima de las inmediatas calles de Silencio, Garro, Grillo... Si continuamos rectos, llegamos a la calle Conde Alperche, tras cruzar la calle del Sepulcro, que tiene un recoveco llamado calle de Esmir, donde se levanta el Palacio del mismo nombre. Un poco mâ”œÃ­s hacia la izquierda, la ribera, y el Ebro. Fuente: Instituto Amatller de Arte Hispâ”œÃ­nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65485900, -0.87545000, '0101000020E6100000F90FE9B7AF03ECBFE23E726BD2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915590095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915590095.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915590095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21383, 'Vista Pilar 1910', '"Vista de la Catedral-Basâ”œÂ¡lica de Nostra Senyora del Pilar de Saragossa". 1910 Imagen de una tarjeta postal de la "Fototipia Castaâ”œâ–’eira y Alvarez" (Madrid), dedicada a Zaragoza. Desde la torre de la Seo, una visual interesante del cogollo urbano en torno a la Seo, la Lonja, y el Pilar, alcanzando la vista hasta el Puente del Ferrocarril, allâ”œÃ­ al fondo. Fuente: Ajuntament de Girona, Servei de Gestiâ”œâ”‚ Documental, Arxius i Publicacions.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16223214726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16223214726.webp', 'https://www.flickr.com/photos/zaragozaantigua/16223214726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21406, 'La Lonja aâ”œâ–’os 10', 'Postal. Vista de la Lonja desde el puente de Piedra. Fuente: www.ebay.com/', 1910, 1910, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65640700, -0.87597800, '0101000020E6100000E17EC0030308ECBFC8EE022505D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25559094936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25559094936.webp', 'https://www.flickr.com/photos/zaragozaantigua/25559094936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21429, 'Ribera del Ebro c.1910', 'Imagen capturada desde la margen izquierda del Ebro, centrada en el tramo de la ribera donde destaca la fachada del complejo del palacio Arzobispal-Seminario diocesano. Detrâ”œÃ­s, el cimborrio y la torre de la catedral de la Seo. A la izquierda, la torre de San Carlos Borromeo sobresale por encima de la antigua casa de Ezmir. o Esmir. A la derecha, el final de la calle de Don Jaime I, con la Casa del Ayuntamiento y la Lonja, y el arranque del puente de Piedra. Por el paseo del Ebro transitan dos jardineras motoras en servicio en la lâ”œÂ¡nea "Circunvalaciâ”œâ”‚n", que coinciden en el desvâ”œÂ¡o que permitâ”œÂ¡a la continuidad del ramal que provenâ”œÂ¡a de la Magdalena (desde la izquierda), y el del Mercado (desde la derecha). Fuente: "Palacio Arzobispal y Torre de la Seo", postal nâ”¬â•‘ 39 de la serie "Zaragoza" de ediciâ”œâ”‚n Thomas, en www.ebay.com/', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65595400, -0.87538500, '0101000020E610000033164D672703ECBF17D7F84CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34079385040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34079385040.webp', 'https://www.flickr.com/photos/zaragozaantigua/34079385040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21444, 'Puente de Piedra c.1910', 'Imagen capturada en el arranque del puente de Piedra desde el paseo del Ebro, con el fondo del Seminario Metropolitano y el Palacio Arzobispal. En primer tâ”œÂ®rmino, medios de locomociâ”œâ”‚n a uâ”œâ–’a de caballerâ”œÂ¡a.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65624000, -0.87590200, '0101000020E6100000200890A16307ECBFDC291DACFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49915047058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49915047058.webp', 'https://www.flickr.com/photos/zaragozaantigua/49915047058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21506, 'Plaza de la Seo 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. La plaza de la Seo desde el arco del Arzobispo". Imagen de la plaza de la Seo capturada desde la calle del Sepulcro, un poco antes de volandero arco del Arzobispo, entre el palacio arzobispal con el templo de la Seo. Es precisamente la inmediatez con el palacio lo que le da a la imagen una perspectiva interesante: asâ”œÂ¡, en lâ”œÂ¡nea recta, el palacio, la Lonja, las viviendas de la calle del Pilar, y el Pilar. La plaza de la Seo queda definida por el espacio abierto y arbolado de la izquierda, con la visual de la fuente de la Samaritana. Por encima de los â”œÃ­rboles sobresale el remate bulboso del peculiar establecimiento "El Pilar" (pintura, esculturas, artesanâ”œÂ¡as), ademâ”œÃ­s de otras viviendas entre esta plaza y la del Pilar. Escenas de la vida cotidiana animan el encuadre: una abuela con su nieta; un vendedor ambulante empujando su carrito del helao; dos "mozos de cuerda" (contratados para llevar cosas de carga); un carro a punto de llegar a Don Jaime I... Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œÃ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65519200, -0.87565000, '0101000020E6100000BEC117265305ECBFE84CDA54DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15589492100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15589492100.webp', 'https://www.flickr.com/photos/zaragozaantigua/15589492100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21630, 'Pl. de la Seo c.1920', 'Imagen capturada en la plaza de la Seo durante el jueves despuâ”œÂ®s de la octava de Pentecostâ”œÂ®s y centrada en la catâ”œâ”‚lica salida en procesiâ”œâ”‚n de la custodia realizada por el platero Pedro Lameison a comienzos del siglo XVI, con aâ”œâ–’adidos posteriores. Al fondo, la barroca fachada que reviste el ingreso principal a la iglesia metropolitana del Salvador. A la izquierda, el desaparecido arco del Arzobispo o volado acceso al palacio arzobispal. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38258355846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38258355846.webp', 'https://www.flickr.com/photos/zaragozaantigua/38258355846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21698, 'Paseo del Ebro 1931', 'En primer tâ”œÂ®rmino, coche participante en el III Gran Premio de Turismo organizado por el Moto Club de Cataluâ”œâ–’a un lluvioso 4 de junio de ese aâ”œâ–’o. Al fondo, el palacio de Ayerbe y el templo del Pilar. A la derecha y fuera de plano, el râ”œÂ¡o Ebro.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65612200, -0.87602100, '0101000020E6100000B37E33315D08ECBFD31742CEFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15473970246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15473970246.webp', 'https://www.flickr.com/photos/zaragozaantigua/15473970246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21710, 'Paseo de la Ribera 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”œÂ¡tulo (la fuente visual asâ”œÂ¡ lo cataloga) no se corresponde con la captura, salvo en que es Zaragoza: se trata de una imagen desde la margen izquierda del Ebro, junto al puente de Hierro, del paseo de la Ribera, con una buena visual de la tremenda fachada que entonces habâ”œÂ¡a, desde la basâ”œÂ¡lica concatedral, la casa de los Infantes, el palacio de los marqueses de Ayerbe, la Posada del Rey, La Lonja, el palacio Arzobispal, la torre y el cimborrio de la Catedral del Salvador en su Epifanâ”œÂ¡a, y el palacio de Esmir y la calle del conde de Alperche. Algunos de estos elementos, transformados, perduran. Otros, no. Fuente visual: Fotografâ”œÂ¡a de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65596000, -0.87530100, '0101000020E6100000BDFE243E7702ECBFF9BD4D7FF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17170406628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17170406628.webp', 'https://www.flickr.com/photos/zaragozaantigua/17170406628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21752, 'Cimborrio Seo 1930', '"Zaragoza. Câ”œâ•‘pula de la Seo" (sic). Imagen del Cimborrio de la Catedral capturada por Antâ”œâ”‚nio Passaporte en una de sus impagables visitas a la ciudad. Esta imagen resulta especialmente interesante, porque permite acotar en el tiempo el derribo del edificio de la "Aduana Vieja", o antigua Casa de hospedaje de la Diputaciâ”œâ”‚n del Reino para diputados foranos. Aunque la imagen tiene un fondo nebuloso que difumina los contornos, es perfectamente visible, a la derecha, el blanquâ”œÂ¡simo, y con regulares vanos, edificio del nuevo "Grupo Escolar Marcelino Lâ”œâ”‚pez Ornat", construido sobre buena parte del solar del antiguo palacio, en la esquina de la calle Palafox, a la derecha, que ademâ”œÃ­s ha sido ensanchada, y la entonces calle del Chantre.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65487900, -0.87539600, '0101000020E61000002D93E1783E03ECBF29EB3713D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22204711298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22204711298.webp', 'https://www.flickr.com/photos/zaragozaantigua/22204711298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21766, 'Arco del Arzobispo 1932', 'Arco del Arzobispo y plaza de la Seo. Al fondo, la Lonja y el Pilar. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65526100, -0.87568800, '0101000020E61000001EFD2FD7A205ECBF11ACAA97DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622124093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622124093.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622124093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21776, 'La Seo 1932', 'Calle del Sepulcro y muros de la Seo. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65511700, -0.87538800, '0101000020E610000078F2E9B12D03ECBFDD06B5DFDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22881366859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22881366859.webp', 'https://www.flickr.com/photos/zaragozaantigua/22881366859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21782, 'Râ”œÂ¡o Ebro 1932', 'Imagen capturada desde el puente del Pilar, con el râ”œÂ¡o Ebro, el puente de Piedra, y buena parte de la antigua fachada de la ciudad en su margen derecha, desde el barrio de La Seo, y hasta la basâ”œÂ¡lica concatedral. Fuente visual: Bildarchiv Foto Marburg, en www.bildindex.de/', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65606100, -0.87532400, '0101000020E6100000C8EC2C7AA702ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23170416029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23170416029.webp', 'https://www.flickr.com/photos/zaragozaantigua/23170416029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23128, 'Monumento al Doctor Cerrada 2006', 'Foto: Guillermo Mestre. Estado del monumento al Doctor Cerrada del parque Primo de Rivera (1929), con el centauro Quirâ”œâ”‚n decapitado. En 2008, la escultura en piedra serâ”œÃ­ sustituida por una de bronce. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.63392500, -0.89683600, '0101000020E6100000BC033C69E1B2ECBFF38E537424D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31489401150.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31489401150.webp', 'https://www.flickr.com/photos/zaragozaantigua/31489401150/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21808, 'Calle del Sepulcro 1937', '"Estos moros que vemos deambular por las calles de Zaragoza son moros "de" Espaâ”œâ–’a, y vienen de la guerra, que para ser eminentemente popular necesitaba que los alfanjes moros se juntaran a nuestras espadas en la lucha contra el comunismo, en la que se ventila, nada mâ”œÃ­s y nada menos, el porvenir de la civilizaciâ”œâ”‚n". Miguel Alluâ”œÂ® Salvador (alcalde de Zaragoza 1927-29). En el dibujo, representaciâ”œâ”‚n de mercenarios soldados norteafricanos de los tabores de la Mehalla de Tetuâ”œÃ­n, llegados a Zaragoza en octubre de 1936, como refuerzo de guerra de los sublevados nacionalistas contra la repâ”œâ•‘blica democrâ”œÃ­tica. Aparecen ubicados de forma idealista delante del mudâ”œÂ®jar "Muro de la Parroquieta" de la iglesia del Salvador, y casi bajo el arco del Arzobispo, en el arranque de la calle del Sepulcro. Un surreal homenaje, sin pretenderlo, a aquellos otros moros que, siglos ha, y siendo indâ”œÂ¡genas, fueron expulsados, u obligados a convertirse a la verdadera religiâ”œâ”‚n. Fuente visual: Revista "Aragâ”œâ”‚n", SIPA, 1937.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65516500, -0.87547300, '0101000020E610000004FEF0F3DF03ECBFEE3D5C72DCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28561213023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28561213023.webp', 'https://www.flickr.com/photos/zaragozaantigua/28561213023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21873, 'P.â”¬â•‘ del Ebro c.1932', 'Despejada y luminosa imagen capturada en el paseo del Ebro entre la Lonja y el puente de Piedra, con una interesante panorâ”œÃ­mica de la antigua fachada urbana en este tramo ribereâ”œâ–’o, desde la Lonja, con sus jardines y estanque, la posada de los Reyes, la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. Sobre el firme, a la izquierda, tramo de vâ”œÂ¡a de la tranviaria lâ”œÂ¡nea del Gâ”œÃ­llego tendido por unas obras en el puente de Piedra, de forma que el trayecto de vuelta se realizaba por el puente de Hierro. A la derecha, tendido de la lâ”œÂ¡nea de Circunvalaciâ”œâ”‚n. Fuente visual: Ediciones Arribas, AMZ. Desde el', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39599563500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39599563500.webp', 'https://www.flickr.com/photos/zaragozaantigua/39599563500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21896, 'Calle del Sepulcro c.1935', 'Inicio de la calle del Sepulcro flanqueado entre el muro mudâ”œÂ®jar de la Parroquieta de la Seo, a la izquierda, y el ilustrado muro del Palacio Arzobispal, cuyo homâ”œâ”‚nimo arco al fondo ofrece una vista que alcanza hasta la calle del Pilar, con el edificio de la Lonja esquinero con la calle de Don Jaime I, e incluso la difuminada silueta de la torre de Nuestra Seâ”œâ–’ora del Pilar del homâ”œâ”‚nimo templo, apuntando hacia arriba. Tras el arco, la plaza de La Seo. En primer tâ”œÂ®rmino, dos infantes atraâ”œÂ¡dos por el artilugio fotogrâ”œÃ­fico que captura la instantâ”œÃ­nea se distraen de los juegos con que otros, mâ”œÃ­s atentos, pasan el rato junto a la singular tracerâ”œÂ¡a mudâ”œÂ®jar que cierra la capilla del arzobispo Luna.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65515000, -0.87550500, '0101000020E6100000DC80CF0F2304ECBFB9FC87F4DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50762703831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50762703831.webp', 'https://www.flickr.com/photos/zaragozaantigua/50762703831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22076, 'Calle Pabostrâ”œÂ¡a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostrâ”œÂ¡a, capturada desde la calle Deâ”œÃ­n. A la izquierda, se abre la calle Lucero. El muro delimita al palacio de los Armijo. Al fondo, visual de la calle Dormer, con el palacio de la Maestranza bien soleado.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65411600, -0.87551500, '0101000020E6100000C00985083804ECBF2AE5B512BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15573381458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15573381458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15573381458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22080, 'Calle Lucero 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la breve calle Lucero, capturada desde la calle Pabostria. Al fondo, la calle Don Juan de Aragâ”œâ”‚n. A la izquierda, el antiguo palacio de los Armijo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65401200, -0.87578400, '0101000020E6100000A585CB2A6C06ECBF85984BAAB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15758884675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15758884675.webp', 'https://www.flickr.com/photos/zaragozaantigua/15758884675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22085, 'Infantes Reales en plaza de la Seo 1951', 'Desde su llegada al Reino de Espaâ”œâ–’a para continuar sus estudios en 1950, los Infantes Juan Carlos y Alfonso de Borbâ”œâ”‚n realizaron diversos viajes tulelados por la geografâ”œÂ¡a peninsular (Madrid, Valencia, Sevilla...) para ir conociendo un paâ”œÂ¡s para ellos extraâ”œâ–’o. En octubre de 1951 vinieron a Zaragoza para visitar el Pilar y la Seo. En la imagen, los infantes Alfonso (10 aâ”œâ–’os de edad) y Juan Carlos (13 aâ”œâ–’os de edad) junto a la puerta de la Catedral del Salvador en su Epifanâ”œÂ¡a, en la plaza de la Seo, que se abre detrâ”œÃ­s de ellos, con el arbolado espacio central en torno a la fuente de la Samaritana, con el caracterâ”œÂ¡stico quiosco de prensa, y los bancos de sentarse. Entre el adoquinado, las vâ”œÂ¡as de la lâ”œÂ¡nea del tranvâ”œÂ¡a giran hacia el puente de Piedra y el Arrabal. A la derecha, la Lonja, y la iluminada esquina del Seminario Diocesano, a punto de trasladarse al nuevo recinto de Casablanca.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65519200, -0.87565000, '0101000020E6100000BEC117265305ECBFE84CDA54DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16335512123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16335512123.webp', 'https://www.flickr.com/photos/zaragozaantigua/16335512123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22112, 'Arco del Deâ”œÃ­n 1951', 'Imagen, entre claroscuros, capturada en la calle del Deâ”œÃ­n, con el Arco del mismo nombre de tenebrista fondo, antes de su radical reinvenciâ”œâ”‚n unos aâ”œâ–’os despuâ”œÂ®s. Es una de esas imâ”œÃ­genes que a finales de los aâ”œâ–’os 50 del pasado siglo se utilizaban para ilustrar la "Vieja Zaragoza", en cualquiera de sus acepciones, por contraposiciâ”œâ”‚n con la "Moderna". Fuente visual: Sebastiâ”œÃ­n Gâ”œâ”‚mez Cortâ”œÂ®s.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22113512675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22113512675.webp', 'https://www.flickr.com/photos/zaragozaantigua/22113512675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22306, 'Puente de Piedra 1962', 'Imagen del Puente de Piedra capturada desde el paseo de la Ribera a la altura del emboque en la calle Don Jaime I. La arcada y el pilar de soporte son los mâ”œÃ­s prâ”œâ”‚ximos a la margen derecha del râ”œÂ¡o. Un par de motos, un tractor, y un autobâ”œâ•‘s de â”œÃ¼greda Automâ”œâ”‚vil, no alcanzan a colapsar el trâ”œÃ­fico, aunque unos aâ”œâ–’os despuâ”œÂ®s sâ”œÂ¡ serâ”œÃ­ posible. Los peatones, bien, gracias. Fuente: www.flickr.com/photos/madridx1306/1340434217/in/photostream/', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65636800, -0.87582800, '0101000020E61000008E791D71C806ECBF0A12DBDD03D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15620175827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15620175827.webp', 'https://www.flickr.com/photos/zaragozaantigua/15620175827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22332, 'Calle del Deâ”œÃ­n aâ”œâ–’os 60', 'Escena teatralizada de rondalla jotera a damas en balcâ”œâ”‚n, localizada en la calle del Deâ”œÃ­n, junto al pasaje arquitrabado desaparecido en los aâ”œâ–’os 70, con el arco del Deâ”œÃ­n al fondo.', 1960, 1960, 1969, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18966133301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18966133301.webp', 'https://www.flickr.com/photos/zaragozaantigua/18966133301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22866, 'Plaza del Pilar 1987', 'Luis Mâ”œÂ¡nguez. 1987. Desde la torre de la Catedral del Salvador, una abierta vista desde la inmediata y arbolada plaza de la Seo, hasta la amplia plaza del Pilar, con sus diferentes sectores (isleta peatonal del monumento de Goya; isleta-aparcamiento frente al Ayuntamiento; plaza-aparcamiento del Gobierno Civil, a la izquierda; explanada peatonal frente al Pilar; isleta-aparcamiento de los cipreses, frente al monumento "A los hâ”œÂ®roes y mâ”œÃ­rtires de Zaragoza. Caâ”œÂ¡dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939". La circulaciâ”œâ”‚n rodada cuarteaba este gran espacio por todos los lados.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665965000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665965000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665965000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22879, 'Calle Lucero 1989', 'Imagen capturada desde el encuentro de las calles Pabostria y Lucero de las traseras de los restos en pie del antiguo palacio de la calle Don Juan de Aragâ”œâ”‚n nâ”¬â•‘ 7, otro ejemplo de la suerte que en esta ciudad han padecido numerosas casas-palacio renacentistas del XVI. Propiedad privada, es declarado en ruina en 1969, y piqueteado un par de aâ”œâ–’os despuâ”œÂ®s, salvo la fachada principal, y una parte de la secundaria. En 1979 se inician tareas de consolidaciâ”œâ”‚n de los restos, primero a cargo del Ministerio de Cultura, luego ya por el Ayuntamiento. Mucho mâ”œÃ­s tarde el edificio es reinventado para habilitar en â”œÂ®l la sede de la reinterpretada instituciâ”œâ”‚n medieval del "Justicia de Aragâ”œâ”‚n". Fuente: Ursula Heredia Lagunas, "Las casas palacio del siglo XVI en Zaragoza" Artigrama, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65414800, -0.87569800, '0101000020E61000000186E5CFB705ECBF355F251FBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17786108646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17786108646.webp', 'https://www.flickr.com/photos/zaragozaantigua/17786108646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22907, 'Plaza San Bruno 1989', 'Vista en altura de la excavaciâ”œâ”‚n arqueolâ”œâ”‚gica en el entorno de la calle Sepulcro y plaza San Bruno. Al fondo, traseras de la Seo y el Palacio Arzobispal. Se hallaron restos del foro y macellum (mercado) romanos, ademâ”œÃ­s del acceso al puerto fluvial. Fuente: "La legislaciâ”œâ”‚n y la gestiâ”œâ”‚n del patrimonio arqueolâ”œâ”‚gico de la ciudad de Zaragoza", Raâ”œâ•‘l Lâ”œâ”‚pez Villa, 2009.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65509300, -0.87492600, '0101000020E61000006D718DCF64FFEBBF556B6116DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22030739371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22030739371.webp', 'https://www.flickr.com/photos/zaragozaantigua/22030739371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23010, 'La Seo 1992', 'Vista del lado sur de la Seo, con la puerta de la calle Pabostrâ”œÂ¡a arriba a la izquierda. Las excavaciones arqueolâ”œâ”‚gicas de su subsuelo muestran la cimentaciâ”œâ”‚n del templo tiberiano del foro (siglo I). Fuente: Nuevos datos para el conocimiento del foro de Caesaraugusta, Empâ”œâ•‘ries 51, 1998.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65456200, -0.87596800, '0101000020E6100000FDF50A0BEE07ECBF289A07B0C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31582810403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31582810403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31582810403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23208, 'Calle Pabostrâ”œÂ¡a 2010', 'Recreaciâ”œâ”‚n mediante montaje fotogrâ”œÃ­fico e infografâ”œÂ¡a de la esquina entre las calles del Deâ”œÃ­n (derecha) y de la Pabostrâ”œÂ¡a. Se trata de una propuesta del grupo municipal de Izquierda Unida en 2010, consistente en convertir la zona en una nueva plaza, eliminando los muros que separan estas calles de un solar sin uso, perteneciente al arzobispado. Estâ”œÃ­ situado en las traseras del Museo de Tapices de la Seo, en los terrenos del antiguo horno de pan de la catedral. La respuesta de los propietarios no se hizo esperar: ese solar serâ”œÃ­ utilizado para ampliar el citado museo, "prâ”œâ”‚ximamente". Fuente visual: Izquierda Unida de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65420900, -0.87552800, '0101000020E6100000E76ED74B5304ECBFDBDFD91EBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33157073460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33157073460.webp', 'https://www.flickr.com/photos/zaragozaantigua/33157073460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23237, 'Mezquita mayor', 'Aspecto de la mezquita-aljama de Saraqusta hacia 1050. Dibujo de J. A. Pâ”œÂ®rez Casas sobre datos de B. Cabaâ”œâ–’ero, J. L. Corral y J. A. Pâ”œÂ®rez Casas. Libro Historia de cuatro ciudades', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65458900, -0.87576400, '0101000020E6100000DE7360394206ECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14814477377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14814477377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14814477377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23239, 'Mezquita Aljama', 'Zaragoza 1118, Mezquita Aljama. Javier Peâ”œâ–’a. "Hanas ibn cAbd Allah as-Sancâ”œÃ­ni construyâ”œâ”‚ la mezquita de la ciudad y levantâ”œâ”‚ su mihrab. Cuando se hizo una ampliaciâ”œâ”‚n de la mezquita-aljama, fue demolido el muro meridional, respetando el mihrab. Excavaron por debajo de â”œÂ®l y lo levantaron sobre dos grandes vigas de madera bajo las cuales colocaron unas columnas tumbadas con el fin de trasladarlo de sitio. Tiraron luego de las dos vigas por medio de cables pero el mismo dâ”œÂ¡a en que se hizo comenzâ”œâ”‚ a agrietarse el mihrab. Al dâ”œÂ¡a siguiente lo aseguraron con cables y volvieron a correrlo hasta el lugar en que hoy sigue emplazado. Por encima de â”œÂ®l y a sus lados construyeron el edificio que lo recubre".(Ahmad ibn cumar al cudri, 393/1003 - 478/1085). "En su mezquita hay un mihrab de un solo bloque de mâ”œÃ­rmol blanco que no existe en la tierra otro como â”œÂ®ste". (Az-Zuhri). En la imagen, reconstrucciâ”œâ”‚n idealizada de la mezquita-aljama de Saraqusta tras la ampliaciâ”œâ”‚n ordenada por Mundir I, primer sultâ”œÃ­n, del zagrâ”œÂ¡ reino de Saraqusta (1018-1022). Asâ”œÂ¡ la encontraron los invasores cristianos.', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65458900, -0.87576400, '0101000020E6100000DE7360394206ECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14980608716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14980608716.webp', 'https://www.flickr.com/photos/zaragozaantigua/14980608716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23243, 'Carlomagno 780', 'La elaboraciâ”œâ”‚n a finales del siglo XI (1180-1190) del poema â”œÂ®pico titulado "Cantar de Roldâ”œÃ­n", supuso un desafâ”œÂ¡o para su-s autor-es, que se vieron en el brete de tener que relatar con la debida precisiâ”œâ”‚n los heroicos eventos desarrollados cuatro siglos antes, en los aâ”œâ–’os 778-780, durante la incursiâ”œâ”‚n peninsular del rey Carlos, que desde el reino de los Francos le trajo hasta la ciudad de Saraqusta. Los cronistas tuvieron que torcer un poco la realidad, parece ser, como ejemplifica el dibujo de la imagen, donde se ilustra la imaginada sumisiâ”œâ”‚n de la ciudad, representada por "Braslimonda", esposa del "monarca" musulmâ”œÃ­n del momento (denominado "Farnagâ”œÃ­n"), ante el rey de los Francos, Carlos, que luego serâ”œÂ¡a llamado Karl der Groâ”œÆ’e (Carlomagno). De tener algâ”œâ•‘n viso de realismo (que no tiene ninguno), esta escena se tendrâ”œÂ¡a que haber escenificado en la puerta norte, o del Puente. En el "Rollan a Saragossa", otro poema provenzal del gâ”œÂ®nero â”œÂ®pico, Roldâ”œÃ­n mantiene en la Saraqusta islâ”œÃ­mica unos encuentros amorosos con la reina Braslimonda, ciertamente tambiâ”œÂ®n â”œÂ®picos, que hacen que al rey Farnagâ”œÃ­n se lo lleven los demonios. No digas que fue un sueâ”œâ–’o. Fuente visual: Biblioteca Universitaria de Heidelberg (www.ub.uni-heidelberg.de/)', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œÃ´RICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25100246541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25100246541.webp', 'https://www.flickr.com/photos/zaragozaantigua/25100246541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23104, 'Calle Gonzalo Calamita 2006', 'A comienzos del siglo XXI, el mal estado de las consultas del Hospital Universitario Miguel Servet, asâ”œÂ¡ como las necesidades de Traumatologâ”œÂ¡a, y el incremento de actividad hospitalaria, hicieron necesario plantear una soluciâ”œâ”‚n global. Inmediato, aunque al otro lado de la calle Gonzalo Calamita, estaba el viejo y desocupado edificio de la Mutualidad General de Funcionarios Civiles del Estado (MUFACE), sobre mâ”œÃ­s de 21000 metros cuadrados. Respetando la estructura, fachadas y cubiertas preexistentes, fue totalmente remodelado para albergar las nuevas consultas externas del Hospital General, de Traumatologâ”œÂ¡a y de Maternidad. Las obras comenzaron en 2004, y en el momento de capturar esta imagen, se acababa de instalar la pasarela sobrevolada de hierro para conectar el hospital (a la derecha) con el remodelado anexo (izquierda), mediante un viaducto a 4,5 metros de altura del suelo, de 38 metros de largo, una altura de 5,38 metros y 3,80 metros de ancho. Fuente: sectorzaragozados.salud.aragon.es/', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.63424300, -0.90070600, '0101000020E610000084F3A96395D2ECBFC45BE7DF2ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24322565039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24322565039.webp', 'https://www.flickr.com/photos/zaragozaantigua/24322565039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23440, 'Casa Armijo 1971', 'Denominada en â”œÂ®poca reciente "Casa Armijo" por el nombre de â”œâ•‘ltima familia que la poseyâ”œâ”‚, estâ”œÃ­ edificada en un solar de varias casas vendidas en 1147 a la Seo por el matrimonio Ponce de Fredalez y Estefanâ”œÂ¡a, destinadas a vivienda de dignidades capitulares. Esta, en concreto, fue vivienda del Arcipreste de la Seo. En 1878, Francisco de Armijo reformâ”œâ”‚ el edificio. En 1971, la Direcciâ”œâ”‚n General de Bellas Artes paralizâ”œâ”‚ el derribo ya iniciado de la casa, conservâ”œÃ­ndose la fachada a Don Juan de Aragâ”œâ”‚n, parte de la recayente a Lucero y sus correspondientes crujâ”œÂ¡as que rodean el patio. En 1979 el Ministerio de Cultura acometiâ”œâ”‚ obras de consolidaciâ”œâ”‚n del edificio con carâ”œÃ­cter de urgencia. En 1984 la Alcaldâ”œÂ¡a-Presidencia del Ayuntamiento aprobâ”œâ”‚ obras de carâ”œÃ­cter urgente (apuntalamientos y consolidaciones). Estas obras fueron dirigidas por la arquitecta municipal â”œÃœrsula Heredia Lagunas, y terminadas en 1989. Posteriormente, los arquitectos Garcâ”œÂ¡a Elorza y Fernandez Ramirez, reinventaban el edificio y lo habilitaban para Sede de la Instituciâ”œâ”‚n "Justicia de Aragâ”œâ”‚n". Mâ”œÃ­s tarde, se instalaron en el edificio dos techumbres mudâ”œÂ®jares procedentes del derribo de un inmueble en calle Cinegio nâ”¬â•‘ 5. En la imagen, el edificio reciâ”œÂ®n salvado de la piqueta total, visto desde la calle Don Juan de Aragâ”œâ”‚n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65389800, -0.87575200, '0101000020E6100000CD02ED0E2906ECBFBC75FEEDB2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14888177222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14888177222.webp', 'https://www.flickr.com/photos/zaragozaantigua/14888177222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-0