INSERT INTO public.photos VALUES (23465, 'Casa Armijo 1971', 'Vista del derribo de Casa Armijo, palacio renacentista entre las calles de Don Juan de Aragâ”œâ”‚n, Lucero y Pabostrâ”œÂ¡a. Tras conservarse la fachada al paralizarse este derribo, se reconstruye como "Palacio del Justicia" dando sede a esta instituciâ”œâ”‚n desde los aâ”œâ–’os noventa. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65397800, -0.87572000, '0101000020E6100000F67F0EF3E505ECBFD926158DB5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23140686302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23140686302.webp', 'https://www.flickr.com/photos/zaragozaantigua/23140686302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23481, 'Casa de Armijo 1985', 'Imagen centrada en las ruinosas traseras de la casa denominada de Armijo, que fuera medieval residencia de dignidades capitulares de la Seo, cuya fachada e ingreso principal era por la calle de Don Juan de Aragâ”œâ”‚n (al fondo de la imagen). La captura se ha realizado antes de que el Ayuntamiento acometiera obras de apuntalamiento y consolidaciâ”œâ”‚n del edificio. A la derecha, fuera de plano, la calle Lucero conducâ”œÂ¡a a la de la Pabostrâ”œÂ¡a. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65403800, -0.87567500, '0101000020E6100000F697DD938705ECBFAE2B6684B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39825805542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39825805542.webp', 'https://www.flickr.com/photos/zaragozaantigua/39825805542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23490, 'Plaza de La Seo c.1889', 'Imagen capturada en la plaza de La Seo, recientemente reurbanizada, y centrada en la fachada del dieciochesco Palacio Arzobispal. A la izquierda, el Seminario Conciliar Metropolitano inaugurado oficialmente en 1848 y construido sobre los restos del antiguo Palacio de la Diputaciâ”œâ”‚n del Reino, que para ello fue terminado de derribar. A la derecha, el Arco del Arzobispo y vista parcial de la fachada del ingreso principal a la catedral de la Seo.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65530200, -0.87582700, '0101000020E610000077853E58C606ECBF6F8099EFE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50103973057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50103973057.webp', 'https://www.flickr.com/photos/zaragozaantigua/50103973057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23496, 'P.â”¬â•‘ de Echegaray y Caballero 1971', 'Imagen capturada en el paseo de Echegaray y Caballero y centrada en la opacada fachada ribereâ”œâ–’a del palacio Arzobispal, construido en terrenos graciosamente regalados a la iglesia por Alfonso I "el Batallador", del que a la izquierda emerge la barroca torre del templo de San Salvador. A la siniestra comienza el solar de la antigua y ya derribada notable casa de los Almonacid/Esmir, cuya desapariciâ”œâ”‚n incluyâ”œâ”‚ ademâ”œÃ­s el derribo del torreâ”œâ”‚n que flanqueaba por ese lado las dependencias arzobispales. A la derecha se nos muestra el inmueble que acogiera el Seminario metropolitano, ocupado en la fecha por diversas secciones de la Acciâ”œâ”‚n Catâ”œâ”‚lica Espaâ”œâ–’ola (Consejo Diocesano, Juventud Femenina, Juventud Masculina, Câ”œÃ­ritas Diocesana, Consejo Diocesano de Hombres...) Ante ella figura la estaciâ”œâ”‚n de servicio "N.â”¬Â¬ S.â”¬Â¬ del Pilar", desde donde a finales del mes de diciembre su trabajador Francisco Jimâ”œÂ®nez Lacarra contemplarâ”œÂ¡a câ”œâ”‚mo se precipitaba en el râ”œÂ¡o Ebro un autobâ”œâ•‘s de emigrantes. En el centro de la imagen un cartel publicitario anuncia a la petrolera norteamericana Caltex Oil S.A.E. Hacia la derecha, fuera de plano, se estacionaban los autobuses que conectaban Zaragoza con las localidades de San Juan de Mozarrifar, Villanueva de Gâ”œÃ­llego, Novillas y Huesca.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65569500, -0.87510800, '0101000020E610000098F90E7EE200ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54273489927.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54273489927.webp', 'https://www.flickr.com/photos/zaragozaantigua/54273489927/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23795, 'El Pilar 1930', 'El Pilar visto desde la torre de la Seo.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65497400, -0.87584300, '0101000020E6100000E3C62DE6E706ECBF7BDD2230D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866304054.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866304054.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866304054/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23796, 'Paseo de la Ribera 1930', '"El Pilar desde la Puerta del â”œÃ¼ngel".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65649700, -0.87596600, '0101000020E6100000D00D4DD9E907ECBF0876FC1708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866417704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866417704.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866417704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23954, 'Jesâ”œâ•‘s atado c.1963', '"Jesâ”œâ•‘s atado a la columna" pasa bajo el arco del Arzobispo, en la plaza de la Seo de Zaragoza. La escultura es de Josâ”œÂ® Bueno, para la cofradâ”œÂ¡a del mismo nombre, que le acompaâ”œâ–’a caracterizada.', 1963, 1963, 1963, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65521100, -0.87564600, '0101000020E610000063F19BC24A05ECBF5F7D3CF4DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14791738670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14791738670.webp', 'https://www.flickr.com/photos/zaragozaantigua/14791738670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23975, 'Timbaleros y clarineros 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 16/04/1974. Maceros, ujieres, timbaleros y clarineros son protocolarias figuras municipales para dar empaque a los actos mâ”œÃ­s solemnes del Ayuntamiento. Los maceros representan el poder y la autoridad y portan las mazas como seâ”œâ–’al de ello. Las mazas municipales datan del siglo XVIII y son obra del platero zaragozano Estrada. Sus antecedentes fueron los alguaciles, con funciones de anunciar y proteger a las autoridades locales. Clarineros y timbaleros quedan como reminiscencia de los heraldos del siglo XVI, con la misiâ”œâ”‚n de hacer notar musicalmente que la ciudad estâ”œÃ­ presente en el acto en el que participan. Cuatro son sus piezas mâ”œÃ­s recurrentes: la "Marcha de la ciudad", de tiempos de Juan II de Aragâ”œâ”‚n (1458-1479); el "Saludo al Ayuntamiento"; la "Marcha Regia"; y "el Pregâ”œâ”‚n". En la imagen, timbaleros y clarineros (con trompeta), junto con dos portaestandartes con el escudo herâ”œÃ­ldico de la ciudad, en un acto oficial en la Catedral de La Seo.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65463400, -0.87558800, '0101000020E61000003CA41820D104ECBFC26C020CCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15227857989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15227857989.webp', 'https://www.flickr.com/photos/zaragozaantigua/15227857989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24052, 'Arco del Deâ”œÃ­n 1930', 'Foto: Miguel Marâ”œÂ¡n Chivite. Procesiâ”œâ”‚n del Domingo de Ramos 13 de abril de 1930, cuando acaba de pasar bajo el arco del Deâ”œÃ­n y gira por la calle de Palafox en su confluencia con la plaza de San Bruno. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65446500, -0.87503500, '0101000020E61000001C5F7B664900ECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31505539974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31505539974.webp', 'https://www.flickr.com/photos/zaragozaantigua/31505539974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
